svg.script:
(function() {
  if (typeof document === 'undefined') return;

  // Track clicks and remove focus outline
  document.querySelectorAll('a[xlink\\:href]').forEach(function(link) {
    link.addEventListener('click', function(e) {
      var section = this.querySelector('.square') ? this.querySelector('.square').id : 'unknown';
      var url = this.getAttribute('xlink:href');

      // Remove focus outline after click
      this.blur();

      // Log to console
      console.log('Bloom\'s Taxonomy Click:', {
        section: section,
        url: url,
        timestamp: new Date().toISOString()
      });

      // Google Analytics tracking
      if (typeof gtag !== 'undefined') {
        gtag('event', 'click', {
          'event_category': 'Blooms Taxonomy',
          'event_label': section,
          'value': 1
        });
      }

      if (typeof ga !== 'undefined') {
        ga('send', 'event', 'Blooms Taxonomy', 'click', section);
      }

      // LocalStorage tracking
      try {
        var clicks = JSON.parse(localStorage.getItem('bloomsClicks') || '[]');
        clicks.push({
          section: section,
          url: url,
          timestamp: new Date().toISOString()
        });
        if (clicks.length > 100) clicks = clicks.slice(-100);
        localStorage.setItem('bloomsClicks', JSON.stringify(clicks));
      } catch(e) {}
    });
  });

  console.log('Bloom\'s Taxonomy Interactive Diagram loaded');
})();
